define("tiny_justify/plugin",["editor_tiny/loader","tiny_justify/configuration","tiny_justify/commands"],function(Loader,Configuration,Commands){"use strict";const pluginName="tiny_justify/plugin";const pluginMetadata={name:pluginName,version:"2026030309"};return new Promise(async resolve=>{const [tinyMCE,setupCommands]=await Promise.all([Loader.getTinyMCE(),Commands.getSetup()]);tinyMCE.PluginManager.add(pluginName,editor=>{setupCommands(editor);return pluginMetadata});resolve([pluginName,Configuration])})});
